// WRONG — fires before React hydration in production:
await page.getByRole('button', { name: 'Sign in' }).click();

// CORRECT:
await page.evaluate(() => {
  const form = document.querySelector('form') as HTMLFormElement | null;
  form?.requestSubmit();
});

test.afterEach(async ({ page }, testInfo) => {
  const tcMatch = testInfo.title.match(/^(LOGIN-\d+)/);
  if (tcMatch) {
    await captureEvidence(page, tcMatch[1], testInfo.status);
  }
});

